SELECT ATTD.GATE_CD , ATTD.BUYER_CD , ATTD.TMPL_NUM , TO_CHAR(ATTD.TMPL_SQ) AS TMPL_SQ , ATTD.TMPL_FILE_NM , ATTD.VALID_PERIOD , (SYSDATE, 'YYYY-MM-DD') AS VALID_START_DATE , CASE WHEN ATTD.VALID_PERIOD = '1년' THEN (ADD_MONTHS(SYSDATE, 12), 'YYYY-MM-DD') WHEN ATTD.VALID_PERIOD = '11개월' THEN (ADD_MONTHS(SYSDATE, 11), 'YYYY-MM-DD') WHEN ATTD.VALID_PERIOD = '10개월' THEN (ADD_MONTHS(SYSDATE, 10), 'YYYY-MM-DD') WHEN ATTD.VALID_PERIOD = '9개월' THEN (ADD_MONTHS(SYSDATE, 9), 'YYYY-MM-DD') WHEN ATTD.VALID_PERIOD = '8개월' THEN (ADD_MONTHS(SYSDATE, 8), 'YYYY-MM-DD') WHEN ATTD.VALID_PERIOD = '7개월' THEN (ADD_MONTHS(SYSDATE, 7), 'YYYY-MM-DD') WHEN ATTD.VALID_PERIOD = '6개월' THEN (ADD_MONTHS(SYSDATE, 6), 'YYYY-MM-DD') WHEN ATTD.VALID_PERIOD = '5개월' THEN (ADD_MONTHS(SYSDATE, 5), 'YYYY-MM-DD') WHEN ATTD.VALID_PERIOD = '4개월' THEN (ADD_MONTHS(SYSDATE, 4), 'YYYY-MM-DD') WHEN ATTD.VALID_PERIOD = '3개월' THEN (ADD_MONTHS(SYSDATE, 3), 'YYYY-MM-DD') WHEN ATTD.VALID_PERIOD = '2개월' THEN (ADD_MONTHS(SYSDATE, 2), 'YYYY-MM-DD') WHEN ATTD.VALID_PERIOD = '1개월' THEN (ADD_MONTHS(SYSDATE, 1), 'YYYY-MM-DD') END AS VALID_END_DATE , ATTD.REQUIRED_FLAG , GETCOMCODE(ATTD.GATE_CD, 'M044', ATTD.REQUIRED_FLAG, '0', #{ses.langCd}) AS REQUIRED_FLAG_NM FROM STOCATTD ATTD WHERE ATTD.GATE_CD = #{ses.gateCd}
AND ATTD.BUYER_CD = #{ses.manageCd}
AND ATTD.BUYER_CD = #{BUYER_CD}
AND ATTD.DEL_FLAG = '0' AND ATTD.USE_FLAG = '1' AND ATTD.DOC_TYPE = 'D02' ORDER BY ATTD.BUYER_CD, ATTD.SORT_SQ

		SELECT *
		  FROM STOCATCH
		 WHERE GATE_CD = #{ses.gateCd}
		   AND UUID IN

            #{item}

           AND DEL_FLAG = '0'

        SELECT USR.USER_ID
          FROM STOCUSER USR
          JOIN STOCOGCM OGCM
	           ON (USR.GATE_CD = OGCM.GATE_CD
	           AND USR.COMPANY_CD = OGCM.BUYER_CD
	           AND OGCM.DEL_FLAG = '0')
         WHERE USR.USER_NM = #{I_USER_NM}
           AND USR.EMAIL = #{I_EMAIL}
           AND REPLACE(USR.CELL_NUM, '-', '') = REPLACE(#{I_CELL_NO}, '-', '')
           AND OGCM.IRS_NUM = #{I_IRS_NO}

        SELECT CVUR.USER_ID
          FROM STOCCVUR CVUR
          JOIN STOCVNGL VNGL
	           ON (CVUR.GATE_CD    = VNGL.GATE_CD
	           AND CVUR.COMPANY_CD = VNGL.VENDOR_CD
	           AND VNGL.DEL_FLAG = '0')
         WHERE CVUR.USER_NM = #{I_USER_NM}
           AND CVUR.EMAIL = #{I_EMAIL}
           AND REPLACE(CVUR.CELL_NUM, '-', '') = REPLACE(#{I_CELL_NO}, '-', '')
           AND VNGL.IRS_NO = #{I_IRS_NO}

        SELECT CVUR.USER_ID
          FROM STOCCVUR CVUR
          JOIN STOCCUST CUST
	           ON (CVUR.GATE_CD    = CUST.GATE_CD
	           AND CVUR.COMPANY_CD = CUST.CUST_CD
	           AND CUST.DEL_FLAG   = '0')
         WHERE CVUR.USER_NM = #{I_USER_NM}
           AND CVUR.EMAIL = #{I_EMAIL}
           AND REPLACE(CVUR.CELL_NUM, '-', '') = REPLACE(#{I_CELL_NO}, '-', '')
           AND CUST.IRS_NUM = #{I_IRS_NO}

SELECT CTRL_USER_ID
  FROM STOCBACP
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CTRL_CD  = 'BR090'
   AND DEL_FLAG = '0'

