		MERGE INTO STOCCVUR A
		USING (SELECT #{ses.gateCd} AS GATE_CD
		            , UPPER((SF_TRIM(#{USER_ID}))) AS USER_ID
		       ) B
            ON (A.GATE_CD = B.GATE_CD
            AND A.USER_ID = B.USER_ID)
		   WHEN MATCHED THEN
		UPDATE SET
		        MOD_DATE = SYSDATE
		      , MOD_USER_ID = #{ses.userId}
		      , DEL_FLAG = '0'
              , COMPANY_CD = #{COMPANY_CD}
              , MNG_YN = (#{MNG_YN}, '0')
              , USER_TYPE = #{USER_TYPE}
              , USER_NM = #{USER_NM}
              , PASSWORD = #{PASSWORD}
              , DEPT_CD = #{DEPT_CD}
              , DEPT_NM = #{DEPT_NM}
              , POSITION_NM = #{POSITION_NM}
              , TEL_NUM = #{TEL_NUM}
              , FAX_NUM = #{FAX_NUM}
              , CELL_NUM = #{CELL_NUM}
              , EMAIL = #{USER_EMAIL}
              , USE_FLAG = #{USE_FLAG}
              , PROGRESS_CD = #{PROGRESS_CD}
              , DUTY_NM = #{DUTY_NM}
              , MAIL_FLAG = #{MAIL_FLAG}
              , SMS_FLAG = #{SMS_FLAG}
              , BLOCK_FLAG = '0'
              , ROLE_TEXT = #{ROLE_TEXT}
		WHEN NOT MATCHED THEN
		INSERT (
            GATE_CD
            , USER_ID
            , REG_DATE
            , REG_USER_ID
            , MOD_DATE
            , MOD_USER_ID
            , DEL_FLAG
            , COMPANY_CD
            , MNG_YN
            , USER_TYPE
            , USER_NM
            , PASSWORD
            , DEPT_CD
            , DEPT_NM
            , POSITION_NM
            , TEL_NUM
            , FAX_NUM
            , CELL_NUM
            , EMAIL
            , USE_FLAG
            , PROGRESS_CD
            , DUTY_NM
            , MAIL_FLAG
            , SMS_FLAG
            , BLOCK_FLAG
            , ROLE_TEXT
        ) VALUES (
             #{ses.gateCd}
            , UPPER((SF_TRIM(#{USER_ID})))
            , SYSDATE
            , #{ses.userId}
            , SYSDATE
            , #{ses.userId}
            , '0'
            , #{COMPANY_CD}
            , (#{MNG_YN}, '0')
            , #{USER_TYPE}
            , #{USER_NM}
            , #{PASSWORD}
            , #{DEPT_CD}
            , #{DEPT_NM}
            , #{POSITION_NM}
            , #{TEL_NUM}
            , #{FAX_NUM}
            , #{CELL_NUM}
            , #{USER_EMAIL}
            , #{USE_FLAG}
            , #{PROGRESS_CD}
            , #{DUTY_NM}
            , #{MAIL_FLAG}
            , #{SMS_FLAG}
            , '0'
            , #{ROLE_TEXT}
        )

