             , MOD_DATE
             , MOD_USER_ID
             , DEL_FLAG
             , USE_FLAG
             , PROGRESS_CD
             , SIGN_STATUS
             , VENDOR_NM
             , VENDOR_ENG_NM
             , IRS_NO
             , REG_TYPE
             , COMPANY_REG_NO
             , BUSINESS_SIZE
             , CEO_USER_NM
             , FOUNDATION_DATE
             , RELAT_YN
             , CORP_TYPE
             , HQ_ZIP_CD
             , HQ_ADDR_1
             , HQ_ADDR_2
             , BUSINESS_TYPE
             , INDUSTRY_TYPE
             , TEL_NO
             , FAX_NO
             , EMAIL
             , HOMEPAGE_URL
             , BUSINESS_REMARK
             , BLOCK_FLAG
             , REMARK_TEXT
             -- 결제정보
             , PAY_PUBLIC_TYPE
             , PAY_CONDITION
             , PAY_TYPE
             -- 관리정보
             , E_BILL_ASP_TYPE
             , TAX_ASP_NM
             , TAX_SEND_TYPE
             , CREDIT_EVAL_COMPANY
             , CREDIT_CD
             , EV_ATT_FILE_NUM
        ) VALUES (
               #{ses.gateCd}
             , #{COMPANY_CD}
             , SYSDATE
             , #{ses.userId}
             , SYSDATE
             , #{ses.userId}
             , '0'
             , '1'
             , #{PROGRESS_CD}
             , #{SIGN_STATUS}
             , #{VENDOR_NM}
             , #{VENDOR_ENG_NM}
             , #{IRS_NUM}
             , #{REG_TYPE}
             , #{COMPANY_REG_NO}
             , #{BUSINESS_SIZE}
             , #{CEO_USER_NM}
             , REPLACE(#{FOUNDATION_DATE}, '-', '')
             , #{RELAT_YN}
             , #{CORP_TYPE}
             , #{HQ_ZIP_CD}
             , #{HQ_ADDR_1}
             , #{HQ_ADDR_2}
             , SUBSTRB(#{BUSINESS_TYPE}, 0, 100)
             , SUBSTRB(#{INDUSTRY_TYPE}, 0, 100)
             , #{TEL_NUM}
             , #{FAX_NUM}
             , #{EMAIL}
             , #{HOMEPAGE_URL}
             , #{BUSINESS_REMARK}
             , '0'
             , #{REMARK_TEXT}
                 -- 결제정보
             , #{PAY_PUBLIC_TYPE}
             , #{PAY_CONDITION}
             , #{PAY_TYPE}
                 -- 관리정보
             , #{E_BILL_ASP_TYPE}
             , #{TAX_ASP_NM}
             , #{TAX_SEND_TYPE}
             , #{CREDIT_EVAL_COMPANY}
             , #{CREDIT_CD}
             , #{EV_ATT_FILE_NUM}
        )

