        MERGE INTO STOCVNFI A
		USING (SELECT #{ses.gateCd} AS GATE_CD
		            , #{COMPANY_CD} AS VENDOR_CD
		            , #{FI_YEAR}    as FI_YEAR
		       ) B
            ON (A.GATE_CD   = B.GATE_CD
            AND A.VENDOR_CD = B.VENDOR_CD
            AND A.FI_YEAR   = B.FI_YEAR)
		   WHEN MATCHED THEN
		UPDATE SET
		        MOD_DATE = SYSDATE
		      , MOD_USER_ID = #{ses.userId}
		      , DEL_FLAG = '0'
              , EVIDENCE_TYPE = #{EVIDENCE_TYPE}
              , OWNER_CAPITAL_AMOUNT = #{OWNER_CAPITAL_AMOUNT}
              , TOT_FUND_AMT = #{TOT_FUND_AMT}
              , TOT_LIAB_AMT = #{TOT_LIAB_AMT}
