               GATE_CD
             , VENDOR_CD
             , FI_YEAR
             , REG_DATE
             , REG_USER_ID
             , MOD_DATE
             , MOD_USER_ID
             , DEL_FLAG
             , EVIDENCE_TYPE
             , OWNER_CAPITAL_AMOUNT
             , TOT_FUND_AMT
             , TOT_LIAB_AMT
             , TOTAL_LIABILITY_RATE
             , CURRENT_ASSET_AMOUNT
             , CURRENT_ASSET_LIABILITY_AMOUNT
             , SALES_AMOUNT
             , NET_PROFIT_AMOUNT
             , ATT_FILE_NUM
        ) VALUES (
               #{ses.gateCd}
             , #{COMPANY_CD}
             , #{FI_YEAR}
             , SYSDATE
             , #{ses.userId}
             , SYSDATE
             , #{ses.userId}
             , '0'
             , #{EVIDENCE_TYPE}
             , #{OWNER_CAPITAL_AMOUNT}
             , #{TOT_FUND_AMT}
             , #{TOT_LIAB_AMT}
             , #{TOTAL_LIABILITY_RATE}
             , #{CURRENT_ASSET_AMOUNT}
             , #{CURRENT_ASSET_LIABILITY_AMOUNT}
             , #{SALES_AMOUNT}
             , #{NET_PROFIT_AMOUNT}
             , #{VNFI_ATT_FILE_NUM}
        )

INSERT INTO STOCVNAP (
       GATE_CD
     , VENDOR_CD
     , SEQ
     , REG_DATE
     , REG_USER_ID
     , MOD_DATE
     , MOD_USER_ID
     , DEL_FLAG
     , PAY_ACC_MNG_NM
     , PAY_ACC_NMG_TEL_NUM
     , PAY_ACC_MNG_EMAIL
     , PAY_BANK
     , PAY_ACCOUNT_NUM
     , PAY_ACCOUNT_USER_NM
     , PAY_ACC_NM
     , ATT_FILE_NUM
) VALUES (
       #{ses.gateCd}
     , #{COMPANY_CD}
     , (SELECT (MAX(TO_NUMBER(SEQ)), 0) + 1
          FROM STOCVNAP
         WHERE GATE_CD = #{ses.gateCd}
           AND VENDOR_CD = #{COMPANY_CD}
           AND DEL_FLAG = '0')
     , SYSDATE
     , #{ses.userId}
     , SYSDATE
     , #{ses.userId}
     , '0'
     , #{PAY_ACC_MNG_NM}
     , #{PAY_ACC_NMG_TEL_NUM}
     , #{PAY_ACC_MNG_EMAIL}
     , #{PAY_BANK}
     , #{PAY_ACCOUNT_NUM}
     , #{PAY_ACCOUNT_USER_NM}
     , #{PAY_ACC_NM}
     , #{PAY_ATT_FILE_NUM}
)

INSERT INTO STOCVNSL (
       GATE_CD
     , COMPANY_CD
     , COMPANY_DEPT_CD
     , SEQ
     , REG_DATE
     , REG_USER_ID
     , MOD_DATE
     , MOD_USER_ID
     , DEL_FLAG
     , SL_TYPE
     , SL_NUM
     , SL_NM
     , ISSUE_NM
     , EXPIRY_DATE
     , ATT_FILE_NUM
) VALUES (
       #{ses.gateCd}
     , #{COMPANY_CD}
     , '0000'
     , (SELECT (MAX(TO_NUMBER(SEQ)), 0) + 1
          FROM STOCVNSL
         WHERE GATE_CD = #{ses.gateCd}
           AND COMPANY_CD = #{COMPANY_CD}
           AND COMPANY_DEPT_CD = '0000'
           AND DEL_FLAG = '0')
     , SYSDATE
     , #{ses.userId}
     , SYSDATE
     , #{ses.userId}
     , '0'
     , #{SL_TYPE}
     , #{SL_NUM}
     , #{SL_NM}
     , #{ISSUE_NM}
     , #{EXPIRY_DATE}
     , #{SL_ATT_FILE_NUM}
)

INSERT INTO STOCATTS (
       GATE_CD
     , BUYER_CD
     , DOC_TYPE
     , TMPL_NUM
     , TMPL_SQ
     , DOC_NUM
     , DOC_CNT
     , VENDOR_CD
     , REG_DATE
     , REG_USER_ID
     , MOD_DATE
     , MOD_USER_ID
     , DEL_FLAG
     , VALID_START_DATE
     , VALID_END_DATE
     , ATT_FILE_NUM
) VALUES (
       #{ses.gateCd}
     , #{TMPL_BUYER_CD}
     , #{DOC_TYPE}
     , #{TMPL_NUM}
     , #{TMPL_SQ}
     , '1'
     , '1'
     , #{COMPANY_CD}
     , SYSDATE
     , #{ses.userId}
     , SYSDATE
     , #{ses.userId}
     , '0'
     , REPLACE(#{VALID_START_DATE}, '-', '')
     , REPLACE(#{VALID_END_DATE}, '-', '')
     , #{ATTS_ATT_FILE_NUM}
)

