UPDATE STOCATCH
   SET FILE_PATH = #{DIR_PATH}
 WHERE GATE_CD = #{ses.gateCd}
   AND UUID = #{UUID}
   AND UUID_SQ = #{UUID_SQ}

UPDATE STOCCVUR
   SET PASSWORD = #{PPDD}
     , PW_WRONG_CNT = 0
     , PW_RESET_FLAG = '1'
     , PW_RESET_DATE = SYSDATE
 WHERE USER_ID = #{P_USER_ID}

UPDATE STOCUSER
   SET PASSWORD = #{PPDD}
     , PW_WRONG_CNT = 0
     , PW_RESET_FLAG = '1'
     , PW_RESET_DATE = SYSDATE
 WHERE USER_ID = #{P_USER_ID}

